  1	import * as React from 'react';
  2	import { StatusBox } from '@odf/shared/generic/status-box';
  3	import {
  4	  Table as PfTable,
  5	  OnSort,
  6	  SortByDirection,
  7	  Tbody,
  8	  Td,
  9	  Th,
 10	  Thead,
 11	  Tr,
 12	  TableVariant,
 13	} from '@patternfly/react-table';
 14	
 15	export type Column = {
 16	  columnName: string;
 17	  className?: string;
 18	  sortFunction?: (a: any, b: any, c: SortByDirection) => any;
 19	};
 20	
 21	export type RowData = [];
 22	
 23	type TableProps = {
 24	  columns: Column[];
 25	  rowRenderer: (rawData: []) => RowData;
 26	  rawData: [];
 27	  ariaLabel: string;
 28	  loaded?: boolean;
 29	  loadError?: any;
 30	  unfilteredData?: [];
 31	  noDataMsg?: React.FC;
 32	  emptyRowMessage?: React.FC;
 33	  variant?: TableVariant;
 34	};
 35	
 36	const Table: React.FC<TableProps> = React.memo(
 37	  ({
 38	    ariaLabel,
 39	    columns,
 40	    rawData,
 41	    rowRenderer,
 42	    loaded = true,
 43	    loadError = null,
 44	    unfilteredData,
 45	    noDataMsg,
 46	    emptyRowMessage,
 47	    variant,
 48	  }) => {
 49	    const [sortIndex, setSortIndex] = React.useState(-1);
 50	    const [sortDirection, setSortDirection] = React.useState<SortByDirection>(
 51	      SortByDirection.asc
 52	    );
 53	
 54	    const onSort: OnSort = (
 55	      _event: React.MouseEvent,
 56	      columnIndex: number,
 57	      sortByDirection: SortByDirection
 58	    ) => {
 59	      setSortIndex(columnIndex);
 60	      setSortDirection(sortByDirection);
 61	    };
 62	
 63	    const sortedData =
 64	      sortIndex !== -1
 65	        ? rawData?.sort((a, b) => {
 66	            return columns[sortIndex].sortFunction(a, b, sortDirection);
 67	          })
 68	        : rawData;
 69	    const rowData = sortedData?.length > 0 ? sortedData.map(rowRenderer) : [];
 70	
 71	    const classNames = columns.map((column) => column.className);
 72	
 73	    const headerColumns = columns.map((column, columnIndex) => {
 74	      const isSortable = !!column.sortFunction;
 75	      const sortParams = isSortable
 76	        ? {
 77	            sort: {
 78	              sortBy: {
 79	                index: sortIndex,
 80	                direction: sortDirection,
 81	              },
 82	              onSort,
 83	              columnIndex,
 84	            },
 85	          }
 86	        : {};
 87	      return (
 88	        <Th key={columnIndex} className={column.className} {...sortParams}>
 89	          {column.columnName}
 90	        </Th>
 91	      );
 92	    });
 93	
 94	    return (
 95	      <StatusBox
 96	        loadError={loadError}
 97	        loaded={loaded}
 98	        EmptyMsg={emptyRowMessage}
 99	        data={rawData}
100	        unfilteredData={unfilteredData}
101	        NoDataEmptyMsg={noDataMsg}
102	        skeleton={<div className="loading-skeleton--table pf-v6-u-mt-lg" />}
103	      >
104	        <PfTable aria-label={ariaLabel} variant={variant}>
105	          <Thead>
106	            <Tr>{headerColumns}</Tr>
107	          </Thead>
108	          <Tbody>
109	            {rowData?.map((row, index) => (
110	              <Tr key={index}>
111	                {row.map((item: React.ReactNode, cellIndex: number) => (
112	                  <Td
113	                    key={`${cellIndex}_${index}`}
114	                    className={classNames[cellIndex]}
115	                  >
116	                    {item}
117	                  </Td>
118	                ))}
119	              </Tr>
120	            ))}
121	          </Tbody>
122	        </PfTable>
123	      </StatusBox>
124	    );
125	  }
126	);
127	
128	export default Table;

